(ns integer-long
  (:require [ys.v0 :refer :all])
  (:refer-clojure :exclude [atom die print read replace reverse set]))

(defn -main [& args]
  (let [op (first args)]
    (case op
      "parse-int"        (println (Integer/parseInt "42"))
      "parse-int-radix"  (println (Integer/parseInt "1010" 2))
      "parse-int-hex"    (println (Integer/parseInt "ff" 16))
      "parse-long"       (println (Long/parseLong "9999999999"))
      "int-max"          (println Integer/MAX_VALUE)
      "int-min"          (println Integer/MIN_VALUE)
      "long-max"         (println Long/MAX_VALUE)
      "long-min"         (println Long/MIN_VALUE)
      "to-bin"           (println (Integer/toBinaryString 42))
      "to-hex"           (println (Integer/toHexString 255))
      "to-oct"           (println (Integer/toOctalString 8))
      "long-to-hex"      (println (Long/toHexString 4096))
      "value-of-int"     (println (Integer/valueOf 7))
      "value-of-str"     (println (Integer/valueOf "7"))
      "ctor-int"         (println (Integer. 5))
      "ctor-str"         (println (Integer. "5"))
      "ctor-long"        (println (Long. 12345))
      "bit-count"        (println (Integer/bitCount 0xFF))
      "leading-zeros"    (println (Integer/numberOfLeadingZeros 1))
      "trailing-zeros"   (println (Integer/numberOfTrailingZeros 8))
      "long-bit-count"   (println (Long/bitCount 0xFFFFFF))
      "imax"             (println (Integer/max 3 7))
      "lmin"             (println (Long/min 3 7))
      "signum-neg"       (println (Integer/signum -5))
      "signum-pos"       (println (Integer/signum 5))
      "signum-zero"      (println (Integer/signum 0))
      (println "usage: integer-long <op>"))))
